mapper.select:
SELECT * FROM volunteer_task WHERE 1=1
AND shelter_id = #{shelterId}
AND task_type = #{taskType}
AND status = #{status}
ORDER BY created_at DESC

SELECT COUNT(DISTINCT vt.task_id) FROM volunteer_task vt
INNER JOIN volunteer_task_record vtr ON vt.task_id = vtr.task_id
WHERE vtr.user_id = #{volunteerUserId}

SELECT * FROM volunteer_task WHERE 1=1
AND shelter_id = #{shelterId}
AND task_id IN (SELECT task_id FROM volunteer_task_record WHERE user_id = #{volunteerUserId})
AND status = #{status}
AND task_type = #{taskType}
ORDER BY created_at DESC

SELECT vt.* FROM volunteer_task vt
INNER JOIN volunteer_task_record vtr ON vt.task_id = vtr.task_id
WHERE vtr.user_id = #{volunteerUserId}
AND vt.status = #{status}
ORDER BY vt.created_at DESC
